text.value:
Napisać aplikację symulującą uproszczony proces zamawiania/płacenia w pewnej firmie wynajmującej samochody na kilometry.

Firma oferuje różne typy samochodów, każdy samochód ma swoją markę/model oraz typ (np. osobowy, dostawczy, zabytkowy, ...). Samochody mogą być zamawiane na daną odległość (tzn. nie dłuższą niż) mierzoną w kilometrach. Ceny za wynajem znajdują się w cenniku. Cennik można modyfikować w dowolnym momencie.

Klienci po rejestracji otrzymują identyfikatory oraz deklarują kwotę pieniędzy, którą chcą wydać na wynajem. Klienci mogą (ale nie muszą) posiadać abonament w firmie. Klienci wybierają samochody i umieszczają je na swojej tzw. liście życzeń. Następnie, być może po jakimś czasie, w celu finalizacji zamówienia przepakowują samochody do koszyka (po uprzednim wyczyszczeniu) i zapłacą za jego zawartość. Każdy klient może mieć tylko 1 listę życzeń i 1 koszyk. Klienci mogą płacić kartą lub przelewem bankowym. Po zapłaceniu, klient ma możliwość dokonania zwrotu (tylko z ostatniej transakcji) części lub całej ilości niewykorzystanych kilometrów.

Aplikacja powinna być napisana tak, aby następujacy, przykładowy program

public class CarshareTest {

	// cena samochodów danego typu z koszyka 
  static double cena(Koszyk k, String markaSamochodu) {
	  /*&lt;- tu trzeba wpisać ciało metody */
  }

  public static void main(String[] args) {

		// cennik
	Cennik cennik = Cennik.pobierzCennik();

		// dodawanie nowych cen do cennika
	cennik.dodaj(OSOBOWY, &quot;Syrena&quot;, 1.5, 2.5, 100, 1.85);  // 1.5 zł za 1 km jeśli klient posiada abonament,
							       // w przeciwnym przypadku: 2.5 zł za 1 km (do 100 km), 1.85 zł za 1 km (od 101-ego kilometra)

    	cennik.dodaj(DOSTAWCZY, &quot;Żuk&quot;, 4, 150, 3);	// 4 zł za 1 km (do 150 km), 
							// 3 zł za 1 km (od 151-tego kilometra)  

    	cennik.dodaj(ZABYTKOWY, &quot;Ford T&quot;, 10);		// 10 zł za 1 km


	cennik.dodaj(DARMO, 50, &quot;Tuk-Tuk&quot;);		// darmowy przejazd tylko dla abonentów (do 50 km)


   		// Klient f1 deklaruje kwotę 900 zł na zamównienia; true oznacza, że klient posiada abonament
    	Klient f1 = new Klient(&quot;f1&quot;, 900, true);

    		// Klient f1 dodaje do listy życzeń różne samochody:
		// &quot;Syrena&quot; typu osobowego na maks. 80 km
		// &quot;Żuk&quot; typu dostawczego na maks. 200 km,		
		// &quot;Lublin&quot; typu zabytkowego na maks. 30 km, 
		// &quot;Tuk-Tuk&quot; typu darmowego na maks. 60 km (ale może tylko do 50 km).  
    	f1.dodaj(new Osobowy(&quot;Syrena&quot;, 80));
	f1.dodaj(new Dostawczy(&quot;Żuk&quot;, 200));
    	f1.dodaj(new Zabytkowy(&quot;Lublin&quot;, 30));
    	f1.dodaj(new Darmo(&quot;Tuk-Tuk&quot;, 60));

		// Lista życzeń klienta f1
	ListaZyczen listaF1 = f1.pobierzListeZyczen();

    	System.out.println(&quot;Lista życzeń klienta &quot; + listaF1);

		// Przed płaceniem, klient przepakuje samochody z listy życzeń do koszyka (po uprzednim wyczyszczeniu).
		// Możliwe, że na liście życzeń są samochody niemające ceny w cenniku,
    		// w takim przypadku nie trafiłyby do koszyka 	
	Koszyk koszykF1 = f1.pobierzKoszyk();
    	f1.przepakuj();

    		// Co jest na liście życzeń klienta f1
    	System.out.println(&quot;Po przepakowaniu, lista życzeń klienta &quot; + f1.pobierzListeZyczen());

		// Co jest w koszyku klienta f1
	System.out.println(&quot;Po przepakowaniu, koszyk klienta &quot; + koszykF1); 

		// Ile wynosi cena wszystkich samochodów typu osobowego w koszyku klienta f1
    	System.out.println(&quot;Samochody Syrena w koszyku klienta f1 kosztowały:  &quot; + cena(koszykF1, &quot;Syrena&quot;));

    		// Klient zapłaci...
    	f1.zaplac(KARTA, false);	// płaci kartą płatniczą, prowizja 1%
					// true oznacza, że w przypadku braku środków aplikacja sam odłoży nadmiarowe kilometry/samochody,
					// false oznacza rezygnację z płacenia razem z wyczyszczeniem koszyka i listy życzeń

    		// Ile klientowi f1 zostało pieniędzy?
    	System.out.println(&quot;Po zapłaceniu, klientowi f1 zostało: &quot; + f1.pobierzPortfel() + &quot; zł&quot;);

    		// Mogło klientowi zabraknąć srodków, wtedy, opcjonalnie, samochody/kilometry mogą być odkładane,
		// w przeciwnym przypadku, koszyk jest pusty po zapłaceniu 
    	System.out.println(&quot;Po zapłaceniu, koszyk klienta &quot; + f1.pobierzKoszyk());
	System.out.println(&quot;Po zapłaceniu, koszyk klienta &quot; + koszykF1); 	

		// Teraz przychodzi klient dakar,
    		// deklaruje 850 zł na zamówienia
    	Klient dakar = new Klient(&quot;dakar&quot;, 850, false);

    		// Zamówił za dużo jak na tę kwotę
	dakar.dodaj(new Dostawczy(&quot;Żuk&quot;, 100));
    	dakar.dodaj(new Zabytkowy(&quot;Ford T&quot;, 50));

    		// Co klient dakar ma na swojej liście życzeń
    	System.out.println(&quot;Lista życzeń klienta &quot; + dakar.pobierzListeZyczen());

	Koszyk koszykDakar = dakar.pobierzKoszyk();
    	dakar.przepakuj();

    		// Co jest na liście życzeń klienta dakar
    	System.out.println(&quot;Po przepakowaniu, lista życzeń klienta &quot; + dakar.pobierzListeZyczen());

	    	// A co jest w koszyku klienta dakar
    	System.out.println(&quot;Po przepakowaniu, koszyk klienta &quot; + dakar.pobierzKoszyk());

		// klient dakar płaci
    	dakar.zaplac(PRZELEW, true);	// płaci przelewem, bez prowizji

		// Ile klientowi dakar zostało pieniędzy? 
	System.out.println(&quot;Po zapłaceniu, klientowi dakar zostało: &quot; + dakar.pobierzPortfel() + &quot; zł&quot;);

		// Co zostało w koszyku klienta dakar (za mało pieniędzy miał)
 	System.out.println(&quot;Po zapłaceniu, koszyk klienta &quot; + koszykDakar);

	dakar.zwroc(DOSTAWCZY, &quot;Żuk&quot;, 50);	// zwrot (do koszyka) 50 km dostawczego &quot;Żuka&quot; z ostatniej transakcji

		// Ile klientowi dakar zostało pieniędzy? 
	System.out.println(&quot;Po zwrocie, klientowi dakar zostało: &quot; + dakar.pobierzPortfel() + &quot; zł&quot;);

		// Co zostało w koszyku klienta dakar
 	System.out.println(&quot;Po zwrocie, koszyk klienta &quot; + koszykDakar); 

   }
}

wyprowadził na konsolę podobne do poniższych wyniki:
Lista życzeń klienta f1:
Syrena, typ: osobowy, ile: 80 km, cena 1.50
Żuk, typ: dostawczy, ile: 200 km, cena 4.00 (do 150), 3.00 (od 151)
Lublin, typ: zabytkowy, ile: 30, ceny brak
Tuk-Tuk, typ: darmowy, ile: 50, ceny 0.00

Po przepakowaniu, lista życzeń klienta f1:
Lublin, typ: zabytkowy, ile: 30, ceny brak

Po przepakowaniu, koszyk klienta f1:
Syrena, typ: osobowy, ile: 80 km, cena 1.50
Żuk, typ: dostawczy, ile: 200 km, cena 4.00 (do 150), 3.00 (od 151)
Tuk-Tuk, typ: darmowy, ile: 50, ceny 0.00

Samochody Syrena w koszyku klienta f1 kosztowały: 120.00 

Po zapłaceniu, klientowi f1 zostało: 21.30 zł

Po zapłaceniu, koszyk klienta f1: -- pusto
Po zapłaceniu, koszyk klienta f1: -- pusto

Lista życzeń klienta dakar:
Żuk, typ: dostawczy, ile: 100, cena 4.00
Ford T, typ: zabytkowy, ile: 50, cena 10.00

Po przepakowaniu, lista życzeń klienta dakar: -- pusto

Po przepakowaniu, koszyk klienta dakar:
Żuk, typ: dostawczy, ile: 100, cena 4.00
Ford T, typ: zabytkowy, ile: 50, cena 10.00

Po zapłaceniu, klientowi dakar zostało: 2.00 zł

Po zapłaceniu, koszyk klienta dakar:
Żuk, typ: dostawczy, ile: 13, cena 4.00

Po zwrocie, klientowi dakar zostało: 202.00 zł

Po zwrocie, koszyk klienta dakar:
Żuk, typ: dostawczy, ile: 63, cena 4.00
Dodawanie nowych typów samochodów musi być zrealizowane w sposób bardzo prosty, w takim przypadku modyfikacja pozostałych klas jest niedozwolona.

Wymagania dodatkowe:
korzystanie z klas abstrakcyjnych/interfejsów oraz z polimorfizmu jest obowiązkowe
pożądana jest minimalizacja kodu klas ListaZyczen oraz Koszyk
istnieje tylko jeden obiekt-cennik/obiekt-koszyk dla klienta, do którego dostęp powinien być realizowany wyłącznie za pomocą metody pobierzCennik()/pobierzKoszyk()
Ważne uwagi:
Być może są samochody niemające ceny w cenniku, wtedy przy przepakowaniu z listy życzeń do koszyka nie są one usuwane z listy życzeń i nie trafią do koszyka.
Niektóre samochody posiadają różne ceny w zależności od ilości zamówionych kilometrów.
Jeśli klient nie ma wystarczającej ilości pieniędzy na całą zawartość koszyka to, zależy od opcji, może zapłacić za część koszyka o ile zapłacona kwota (za dany samochód) jest wielokrotnością ceny tego samochodu za 1 km (zgodnie z cennikiem), w takim przypadku o wyborze samochodów/kilometrów do zapłacenia zadecyduje aplikacja.
Przy płaceniu kartą płatniczą klient zapłaci dodatkowo 1% prowizji.
Przy zwrocie samochodów/kilometrów z ostatniej transakcji, aplikacja powinna zwrócić klientowi właściwą ilość środków uwzględniając faktycznie niezwrócone kilometry (zgodnie z cennikiem). Nie ma zwrotu prowizji.
Zdefiniowanie odpowiedniej metody toString() w niektórych klasach jest obowiązkowe.
Aplikacja powinna działać dla dowolnych danych a nie tylko dla tych podanych w powyższym teście. Przykładowy program nie uwzględnia wszystkich możliwych sytuacji podanych w opisie zadania.

Oto implementacja aplikacji symulującej proces zamawiania/płacenia w firmie wynajmującej samochody na kilometry, zgodnie z podanymi wymaganiami:

```java
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

enum TypPojazdu {
    OSOBOWY, DOSTAWCZY, ZABYTKOWY, DARMO
}

enum MetodaPlatnosci {
    KARTA, PRZELEW
}

class Cennik {
    private static Cennik instance;
    private Map<String, double[]> ceny;

    private Cennik() {
        ceny = new HashMap<>();
    }

    public static Cennik pobierzCennik() {
        if (instance == null) {
            instance = new Cennik();
        }
        return instance;
    }

    public double[] pobierzCene(String nazwa) {
        return ceny.get(nazwa);
    }

    public void dodaj(TypPojazdu typ, String nazwa, double cenaZAbonamentem, double cenaBezAbonamentu, int limitKm, double cenaPoLimicie) {
        ceny.put(nazwa, new double[]{cenaZAbonamentem, cenaBezAbonamentu, (double) limitKm, cenaPoLimicie});
    }

    public void dodaj(TypPojazdu typ, String nazwa, double cenaDoLimitu, int limitKm, double cenaPoLimicie) {
        ceny.put(nazwa, new double[]{cenaDoLimitu, cenaDoLimitu, (double) limitKm, cenaPoLimicie});
    }

    public void dodaj(TypPojazdu typ, String nazwa, double cenaZaKm) {
        ceny.put(nazwa, new double[]{cenaZaKm, cenaZaKm, 0, cenaZaKm});
    }
}

abstract class Pojazd {
    protected String marka;
    protected int maxKilometry;

    public Pojazd(String marka, int maxKilometry) {
        this.marka = marka;
        this.maxKilometry = maxKilometry;
    }

    public abstract TypPojazdu pobierzTypPojazdu();

    @Override
    public String toString() {
        return marka + ", typ: " + getClass().getSimpleName() + ", ile: " + maxKilometry + " km";
    }
}

class Osobowy extends Pojazd {
    public Osobowy(String marka, int maxKilometry) {
        super(marka, maxKilometry);
    }

    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.OSOBOWY;
    }
}

class Zabytkowy extends Pojazd {
    public Zabytkowy(String marka, int maxKilometry) {
        super(marka, maxKilometry);
    }

    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.ZABYTKOWY;
    }
}

class Dostawczy extends Pojazd {
    public Dostawczy(String marka, int maxKilometry) {
        super(marka, maxKilometry);
    }

    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.DOSTAWCZY;
    }
}

class Darmo extends Pojazd {
    public Darmo(String marka, int maxKilometry) {
        super(marka, Math.min(maxKilometry, 50));
    }

    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.DARMO;
    }
}

class ListaZyczen {
    private List<Pojazd> lista;

    public ListaZyczen() {
        lista = new ArrayList<>();
    }

    public void dodaj(Pojazd pojazd) {
        lista.add(pojazd);
    }

    public void usun(Pojazd pojazd) {
        lista.remove(pojazd);
    }

    public void wyczysc() {
        lista.clear();
    }

    public List<Pojazd> pobierzListeZyczen() {
        return lista;
    }

    @Override
    public String toString() {
        StringBuilder result = new StringBuilder();
        if (lista.isEmpty()) {
            return "--- lista życzeń jest pusta";
        }
        for (Pojazd p : lista) {
            Cennik cennik = Cennik.pobierzCennik();
            double[] ceny = cennik.pobierzCene(p.marka);
            String cenaStr = "";
            if (ceny != null) {
                switch (p.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        cenaStr = "cena " + ceny[0];
                        break;
                    case DOSTAWCZY:
                        cenaStr = "cena " + ceny[0] + " (do " + (int) ceny[2] + "), " + ceny[3] + " (od " + ((int) ceny[2] + 1) + ")";
                        break;
                    case ZABYTKOWY:
                        cenaStr = "cena " + ceny[0];
                        break;
                    case DARMO:
                        cenaStr = "ceny 0.00";
                        break;
                }
            } else {
                cenaStr = "ceny brak";
            }
            result.append(p.toString()).append(", ").append(cenaStr).append("\n");
        }
        return result.toString();
    }
}

class Koszyk {
    private List<Pojazd> listaKoszyk;

    public Koszyk() {
        listaKoszyk = new ArrayList<>();
    }

    public void przepakuj(ListaZyczen listaZyczen) {
        listaKoszyk.clear();
        Cennik cennik = Cennik.pobierzCennik();
        for (Pojazd p : listaZyczen.pobierzListeZyczen()) {
            if (cennik.pobierzCene(p.marka) != null) {
                listaKoszyk.add(p);
            }
        }
    }

    public void wyczysc() {
        listaKoszyk.clear();
    }

    public double obliczCene() {
        double cena = 0;
        Cennik cennik = Cennik.pobierzCennik();
        for (Pojazd p : listaKoszyk) {
            double[] ceny = cennik.pobierzCene(p.marka);
            if (ceny != null) {
                switch (p.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        cena += ceny[0] * p.maxKilometry;
                        break;
                    case DOSTAWCZY:
                        if (p.maxKilometry <= ceny[2]) {
                            cena += ceny[0] * p.maxKilometry;
                        } else {
                            cena += ceny[0] * ceny[2] + ceny[3] * (p.maxKilometry - ceny[2]);
                        }
                        break;
                    case ZABYTKOWY:
                        cena += ceny[0] * p.maxKilometry;
                        break;
                    case DARMO:
                        break;
                }
            }
        }
        return cena;
    }

    public double obliczCene(String markaSamochodu) {
        double cena = 0;
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(markaSamochodu);
        if (ceny != null) {
            for (Pojazd p : listaKoszyk) {
                if (p.marka.equals(markaSamochodu)) {
                    switch (p.pobierzTypPojazdu()) {
                        case OSOBOWY:
                            cena += ceny[0] * p.maxKilometry;
                            break;
                        case DOSTAWCZY:
                            if (p.maxKilometry <= ceny[2]) {
                                cena += ceny[0] * p.maxKilometry;
                            } else {
                                cena += ceny[0] * ceny[2] + ceny[3] * (p.maxKilometry - ceny[2]);
                            }
                            break;
                        case ZABYTKOWY:
                            cena += ceny[0] * p.maxKilometry;
                            break;
                        case DARMO:
                            break;
                    }
                }
            }
        }
        return cena;
    }

    public void odkladanieNadmiaru(double nadmiar) {
        Cennik cennik = Cennik.pobierzCennik();
        List<Pojazd> doUsuniecia = new ArrayList<>();
        for (Pojazd p : listaKoszyk) {
            double[] ceny = cennik.pobierzCene(p.marka);
            if (ceny != null) {
                double cenaZa1Km;
                switch (p.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        cenaZa1Km = ceny[0];
                        break;
                    case DOSTAWCZY:
                        if (p.maxKilometry <= ceny[2]) {
                            cenaZa1Km = ceny[0];
                        } else {
                            cenaZa1Km = ceny[3];
                        }
                        break;
                    case ZABYTKOWY:
                        cenaZa1Km = ceny[0];
                        break;
                    case DARMO:
                        cenaZa1Km = 0;
                        break;
                    default:
                        cenaZa1Km = 0;
                }
                int maxKmDoZaplaty = (int) (nadmiar / cenaZa1Km);
                if (maxKmDoZaplaty < p.maxKilometry) {
                    p.maxKilometry = maxKmDoZaplaty;
                    nadmiar -= maxKmDoZaplaty * cenaZa1Km;
                } else {
                    nadmiar -= p.maxKilometry * cenaZa1Km;
                    doUsuniecia.add(p);
                }
            }
        }
        listaKoszyk.removeAll(doUsuniecia);
    }

    public void zwroc(TypPojazdu typ, String nazwa, int km) {
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(nazwa);
        if (ceny != null) {
            for (Pojazd p : listaKoszyk) {
                if (p.marka.equals(nazwa) && p.pobierzTypPojazdu() == typ) {
                    double cenaZa1Km;
                    switch (typ) {
                        case OSOBOWY:
                            cenaZa1Km = ceny[0];
                            break;
                        case DOSTAWCZY:
                            if (p.maxKilometry <= ceny[2]) {
                                cenaZa1Km = ceny[0];
                            } else {
                                cenaZa1Km = ceny[3];
                            }
                            break;
                        case ZABYTKOWY:
                            cenaZa1Km = ceny[0];
                            break;
                        case DARMO:
                            cenaZa1Km = 0;
                            break;
                        default:
                            cenaZa1Km = 0;
                    }
                    p.maxKilometry += km;
                    break;
                }
            }
        }
    }

    @Override
    public String toString() {
        StringBuilder result = new StringBuilder();
        if (listaKoszyk.isEmpty()) {
            return "-- pusto";
        }
        for (Pojazd p : listaKoszyk) {
            result.append(p.toString()).append("\n");
        }
        return result.toString();
    }
}

class Klient {
    private String id;
    private double portfel;
    private boolean abonament;
    private ListaZyczen listaZyczen;
    private Koszyk koszyk;

    public Klient(String id, double portfel, boolean abonament) {
        this.id = id;
        this.portfel = portfel;
        this.abonament = abonament;
        this.listaZyczen = new ListaZyczen();
        this.koszyk = new Koszyk();
    }

    public void dodaj(Pojazd pojazd) {
        listaZyczen.dodaj(pojazd);
    }

    public void przepakuj() {
        koszyk.przepakuj(listaZyczen);
        listaZyczen.wyczysc();
    }

    public ListaZyczen pobierzListeZyczen() {
        return listaZyczen;
    }

    public Koszyk pobierzKoszyk() {
        return koszyk;
    }

    public double pobierzPortfel() {
        return portfel;
    }

    public String getId() {
        return id;
    }

    public void zaplac(MetodaPlatnosci metoda, boolean odkladanieNadmiaru) {
        double doZaplaty = koszyk.obliczCene();
        if (metoda == MetodaPlatnosci.KARTA) {
            doZaplaty *= 1.01; // 1% prowizji
        }
        if (doZaplaty <= portfel) {
            portfel -= doZaplaty;
            koszyk.wyczysc();
