class ListaZyczen {
    private List&lt;Pojazd&gt; lista;

    public ListaZyczen() {
        lista = new ArrayList&lt;&gt;();
    }

    public void dodaj(Pojazd pojazd) {
        lista.add(pojazd);
    }

    public void usun(Pojazd pojazd) {
        lista.remove(pojazd);
    }

    public void wyczysc() {
        lista.clear();
    }

    public List&lt;Pojazd&gt; pobierzListeZyczen() {
        return lista;
    }

    @Override
    public String toString() {
        StringBuilder result = new StringBuilder();
        if (lista.isEmpty()) {
            return &quot;--- lista życzeń jest pusta&quot;;
        }
        for (Pojazd p : lista) {
            Cennik cennik = Cennik.pobierzCennik();
            double[] ceny = cennik.pobierzCene(p.marka);
            String cenaStr = &quot;&quot;;
            if (ceny != null) {
                switch (p.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        cenaStr = &quot;cena &quot; + ceny[0];
                        break;
                    case DOSTAWCZY:
                        cenaStr = &quot;cena &quot; + ceny[0] + &quot; (do &quot; + (int) ceny[2] + &quot;), &quot; + ceny[3] + &quot; (od &quot; + ((int) ceny[2] + 1) + &quot;)&quot;;
                        break;
                    case ZABYTKOWY:
                        cenaStr = &quot;cena &quot; + ceny[0];
                        break;
                    case DARMO:
                        cenaStr = &quot;ceny 0.00&quot;;
                        break;
                }
            } else {
                cenaStr = &quot;ceny brak&quot;;
            }
            result.append(p.toString()).append(&quot;, &quot;).append(cenaStr).append(&quot;\n&quot;);
        }
        return result.toString();
    }
}

class Koszyk {
    private List&lt;Pojazd&gt; listaKoszyk;
    private boolean abonament;

    public Koszyk(boolean abonament) {
        listaKoszyk = new ArrayList&lt;&gt;();
        this.abonament=abonament;
    }

    public void przepakuj(ListaZyczen listaZyczen) {
        listaKoszyk.clear();
        Cennik cennik = Cennik.pobierzCennik();
        for (Pojazd p : listaZyczen.pobierzListeZyczen()) {
            if (cennik.pobierzCene(p.marka) != null) {
                listaKoszyk.add(p);
            }
        }
    }

    public void wyczysc() {
        listaKoszyk.clear();
    }

    public double obliczCene() {
        double cena = 0;
        Cennik cennik = Cennik.pobierzCennik();
        for (Pojazd p : listaKoszyk) {
            double[] ceny = cennik.pobierzCene(p.marka);
            if (ceny != null) {
                switch (p.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        cena += ceny[abonament ? 0 : 1] * p.maxKilometry;
                        break;
                    case DOSTAWCZY:
                        if (p.maxKilometry &lt;= ceny[2]) {
                            cena += ceny[0] * p.maxKilometry;
                        } else {
                            cena += ceny[0] * ceny[2] + ceny[3] * (p.maxKilometry - ceny[2]);
                        }
                        break;
                    case ZABYTKOWY:
                        cena += ceny[0] * p.maxKilometry;
                        break;
                    case DARMO:
                        break;
                }
            }
        }
        return cena;
    }

    public double obliczCene(String markaSamochodu) {
        double cena = 0;
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(markaSamochodu);
        if (ceny != null) {
            for (Pojazd p : listaKoszyk) {
                if (p.marka.equals(markaSamochodu)) {
                    switch (p.pobierzTypPojazdu()) {
                        case OSOBOWY:
                            cena += ceny[abonament ? 0 : 1] * p.maxKilometry;
                            break;
                        case DOSTAWCZY:
                            if (p.maxKilometry &lt;= ceny[2]) {
                                cena += ceny[0] * p.maxKilometry;
                            } else {
                                cena += ceny[0] * ceny[2] + ceny[3] * (p.maxKilometry - ceny[2]);
                            }
                            break;
                        case ZABYTKOWY:
                            cena += ceny[0] * p.maxKilometry;
                            break;
                        case DARMO:
                            break;
                    }
                }
            }
        }
        return cena;
    }

    public void odkladanieNadmiaru(double nadmiar) {
        Cennik cennik = Cennik.pobierzCennik();
        List&lt;Pojazd&gt; doUsuniecia = new ArrayList&lt;&gt;();
        for (Pojazd p : listaKoszyk) {
            double[] ceny = cennik.pobierzCene(p.marka);
            if (ceny != null) {
                double cenaZa1Km;
                switch (p.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        cenaZa1Km = ceny[abonament ? 0 : 1];
                        break;
                    case DOSTAWCZY:
                        if (p.maxKilometry &lt;= ceny[2]) {
                            cenaZa1Km = ceny[0];
                        } else {
                            cenaZa1Km = ceny[3];
                        }
                        break;
                    case ZABYTKOWY:
                        cenaZa1Km = ceny[0];
                        break;
                    case DARMO:
                        cenaZa1Km = 0;
                        break;
                    default:
                        cenaZa1Km = 0;
                }
                int maxKmDoZaplaty = (int) (nadmiar / cenaZa1Km);
                if (maxKmDoZaplaty &lt; p.maxKilometry) {
                    p.maxKilometry = maxKmDoZaplaty;
                    nadmiar -= maxKmDoZaplaty * cenaZa1Km;
                } else {
                    nadmiar -= p.maxKilometry * cenaZa1Km;
                    doUsuniecia.add(p);
                }
            }
        }
        listaKoszyk.removeAll(doUsuniecia);
    }

    public void zwroc(TypPojazdu typ, String nazwa, int km) {
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(nazwa);
        if (ceny != null) {
            for (Pojazd p : listaKoszyk) {
                if (p.marka.equals(nazwa) &amp;&amp; p.pobierzTypPojazdu() == typ) {
                    double cenaZa1Km;
                    switch (typ) {
                        case OSOBOWY:
                            cenaZa1Km = ceny[abonament ? 0 : 1];
                            break;
                        case DOSTAWCZY:
                            if (p.maxKilometry &lt;= ceny[2]) {
                                cenaZa1Km = ceny[0];
                            } else {
                                cenaZa1Km = ceny[3];
                            }
                            break;
                        case ZABYTKOWY:
                            cenaZa1Km = ceny[0];
                            break;
                        case DARMO:
                            cenaZa1Km = 0;
                            break;
                        default:
                            cenaZa1Km = 0;
                    }
                    p.maxKilometry += km;
                    break;
                }
            }
        }
    }

    @Override
    public String toString() {
        StringBuilder result = new StringBuilder();
        if (listaKoszyk.isEmpty()) {
            return &quot;-- pusto&quot;;
        }
        for (Pojazd p : listaKoszyk) {
            result.append(p.toString()).append(&quot;\n&quot;);
        }
        return result.toString();
    }
}

class Klient {
    private String id;
    private double portfel;
    private boolean abonament;
    private ListaZyczen listaZyczen;
    private Koszyk koszyk;

    public Klient(String id, double portfel, boolean abonament) {
        this.id = id;
        this.portfel = portfel;
        this.abonament = abonament;
        this.listaZyczen = new ListaZyczen();
        this.koszyk = new Koszyk(abonament);
    }

    public void dodaj(Pojazd pojazd) {
        listaZyczen.dodaj(pojazd);
    }

    public void przepakuj() {
        koszyk.przepakuj(listaZyczen);
        listaZyczen.wyczysc();
    }

    public ListaZyczen pobierzListeZyczen() {
        return listaZyczen;
    }

    public Koszyk pobierzKoszyk() {
        return koszyk;
    }

    public double pobierzPortfel() {
        return portfel;
    }

    public String getId() {
        return id;
    }

    public void zaplac(MetodaPlatnosci metoda, boolean odkladanieNadmiaru) {
        double doZaplaty = koszyk.obliczCene(abonament);
        if (metoda == MetodaPlatnosci.KARTA) {
            doZaplaty *= 1.01; // 1% prowizji
        }
        if (doZaplaty &lt;= portfel) {
            portfel -= doZaplaty;
            koszyk.wyczysc();
        } else {
            if (odkladanieNadmiaru) {
                double nadmiar = portfel - doZaplaty;
                koszyk.odkladanieNadmiaru(nadmiar, abonament);
                portfel = 0;
            } else {
                koszyk.wyczysc();
            }
        }
    }

    public void zwroc(TypPojazdu typ, String nazwa, int km) {
        koszyk.zwroc(typ, nazwa, km, abonament);
    }

    public String toStringZListaZyczen() {
        return id + &quot;\n&quot; + listaZyczen.toString();
    }
}

    // cena samochodów danego typu z koszyka
    static double cena(Koszyk k, String markaSamochodu) {
        return k.obliczCene(markaSamochodu, abonament);
    }

    public static void main(String[] args) {

        // cennik
        Cennik cennik = Cennik.pobierzCennik();

        // dodawanie nowych cen do cennika
        cennik.dodaj(TypPojazdu.OSOBOWY, &quot;Syrena&quot;, 1.5, 2.5, 100, 1.85);  // 1.5 zł za 1 km jeśli klient posiada abonament,
        // w przeciwnym przypadku: 2.5 zł za 1 km (do 100 km), 1.85 zł za 1 km (od 101-ego kilometra)

        cennik.dodaj(TypPojazdu.DOSTAWCZY, &quot;Żuk&quot;, 4, 150, 3);	// 4 zł za 1 km (do 150 km),
        // 3 zł za 1 km (od 151-tego kilometra)

        cennik.dodaj(TypPojazdu.ZABYTKOWY, &quot;Ford T&quot;, 10);		// 10 zł za 1 km


        cennik.dodaj(TypPojazdu.DARMO, 50, &quot;Tuk-Tuk&quot;);		// darmowy przejazd tylko dla abonentów (do 50 km)


        // Klient f1 deklaruje kwotę 900 zł na zamównienia; true oznacza, że klient posiada abonament
        Klient f1 = new Klient(&quot;f1&quot;, 900, true);

        // Klient f1 dodaje do listy życzeń różne samochody:
        // &quot;Syrena&quot; typu osobowego na maks. 80 km
        // &quot;Żuk&quot; typu dostawczego na maks. 200 km,
        // &quot;Lublin&quot; typu zabytkowego na maks. 30 km,
        // &quot;Tuk-Tuk&quot; typu darmowego na maks. 60 km (ale może tylko do 50 km).
        f1.dodaj(new Osobowy(&quot;Syrena&quot;, 80));
        f1.dodaj(new Dostawczy(&quot;Żuk&quot;, 200));
        f1.dodaj(new Zabytkowy(&quot;Lublin&quot;, 30));
        f1.dodaj(new Darmo(&quot;Tuk-Tuk&quot;, 60));

        // Lista życzeń klienta f1
        ListaZyczen listaF1 = f1.pobierzListeZyczen();

        System.out.println(&quot;Lista życzeń klienta &quot; + listaF1);

        // Przed płaceniem, klient przepakuje samochody z listy życzeń do koszyka (po uprzednim wyczyszczeniu).
        // Możliwe, że na liście życzeń są samochody niemające ceny w cenniku,
        // w takim przypadku nie trafiłyby do koszyka
        Koszyk koszykF1 = f1.pobierzKoszyk();
        f1.przepakuj();

        // Co jest na liście życzeń klienta f1
        System.out.println(&quot;Po przepakowaniu, lista życzeń klienta &quot; + f1.pobierzListeZyczen());

        // Co jest w koszyku klienta f1
        System.out.println(&quot;Po przepakowaniu, koszyk klienta &quot; + koszykF1);

        // Ile wynosi cena wszystkich samochodów typu osobowego w koszyku klienta f1
        System.out.println(&quot;Samochody Syrena w koszyku klienta f1 kosztowały:  &quot; + cena(koszykF1, &quot;Syrena&quot;));

        // Klient zapłaci...
        f1.zaplac(MetodaPlatnosci.KARTA, false);	// płaci kartą płatniczą, prowizja 1%
        // true oznacza, że w przypadku braku środków aplikacja sam odłoży nadmiarowe kilometry/samochody,
        // false oznacza rezygnację z płacenia razem z wyczyszczeniem koszyka i listy życzeń

        // Ile klientowi f1 zostało pieniędzy?
        System.out.println(&quot;Po zapłaceniu, klientowi f1 zostało: &quot; + f1.pobierzPortfel() + &quot; zł&quot;);

        // Mogło klientowi zabraknąć srodków, wtedy, opcjonalnie, samochody/kilometry mogą być odkładane,
        // w przeciwnym przypadku, koszyk jest pusty po zapłaceniu
        System.out.println(&quot;Po zapłaceniu, koszyk klienta &quot; + f1.pobierzKoszyk());
        System.out.println(&quot;Po zapłaceniu, koszyk klienta &quot; + koszykF1);

        // Teraz przychodzi klient dakar,
        // deklaruje 850 zł na zamówienia
        Klient dakar = new Klient(&quot;dakar&quot;, 850, false);

        // Zamówił za dużo jak na tę kwotę
        dakar.dodaj(new Dostawczy(&quot;Żuk&quot;, 100));
        dakar.dodaj(new Zabytkowy(&quot;Ford T&quot;, 50));

        // Co klient dakar ma na swojej liście życzeń
        System.out.println(&quot;Lista życzeń klienta &quot; + dakar.pobierzListeZyczen());

        Koszyk koszykDakar = dakar.pobierzKoszyk();
        dakar.przepakuj();

        // Co jest na liście życzeń klienta dakar
        System.out.println(&quot;Po przepakowaniu, lista życzeń klienta &quot; + dakar.pobierzListeZyczen());

        // A co jest w koszyku klienta dakar
        System.out.println(&quot;Po przepakowaniu, koszyk klienta &quot; + dakar.pobierzKoszyk());

        // klient dakar płaci
        dakar.zaplac(MetodaPlatnosci.PRZELEW, true);	// płaci przelewem, bez prowizji

        // Ile klientowi dakar zostało pieniędzy?
        System.out.println(&quot;Po zapłaceniu, klientowi dakar zostało: &quot; + dakar.pobierzPortfel() + &quot; zł&quot;);

        // Co zostało w koszyku klienta dakar (za mało pieniędzy miał)
        System.out.println(&quot;Po zapłaceniu, koszyk klienta &quot; + koszykDakar);

        dakar.zwroc(TypPojazdu.DOSTAWCZY, &quot;Żuk&quot;, 50);	// zwrot (do koszyka) 50 km dostawczego &quot;Żuka&quot; z ostatniej transakcji

        // Ile klientowi dakar zostało pieniędzy?
        System.out.println(&quot;Po zwrocie, klientowi dakar zostało: &quot; + dakar.pobierzPortfel() + &quot; zł&quot;);

        // Co zostało w koszyku klienta dakar
        System.out.println(&quot;Po zwrocie, koszyk klienta &quot; + koszykDakar);

    }
}

