            double[] ceny = cennik.pobierzCene(p.marka);
            if (ceny != null) {
                switch (p.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        cena += ceny[abonament ? 0 : 1] * p.maxKilometry;
                        break;
                    case DOSTAWCZY:
                        if (p.maxKilometry <= ceny[2]) {
                            cena += ceny[0] * p.maxKilometry;
                        } else {
                            cena += ceny[0] * ceny[2] + ceny[3] * (p.maxKilometry - ceny[2]);
                        }
                        break;
                    case ZABYTKOWY:
                        cena += ceny[0] * p.maxKilometry;
                        break;
                    case DARMO:
                        break;
                }
            }
        }
        return cena;
    }

    public double obliczCene(String markaSamochodu) {
        double cena = 0;
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(markaSamochodu);
        if (ceny != null) {
            for (Pojazd p : listaKoszyk) {
                if (p.marka.equals(markaSamochodu)) {
                    switch (p.pobierzTypPojazdu()) {
                        case OSOBOWY:
                            cena += ceny[abonament ? 0 : 1] * p.maxKilometry;
                            break;
                        case DOSTAWCZY:
                            if (p.maxKilometry <= ceny[2]) {
                                cena += ceny[0] * p.maxKilometry;
                            } else {
                                cena += ceny[0] * ceny[2] + ceny[3] * (p.maxKilometry - ceny[2]);
                            }
                            break;
                        case ZABYTKOWY:
                            cena += ceny[0] * p.maxKilometry;
                            break;
                        case DARMO:
                            break;
                    }
                }
            }
        }
        return cena;
    }

    public void odkladanieNadmiaru(double nadmiar) {
        Cennik cennik = Cennik.pobierzCennik();
        List<Pojazd> doUsuniecia = new ArrayList<>();
        for (Pojazd p : listaKoszyk) {
            double[] ceny = cennik.pobierzCene(p.marka);
            if (ceny != null) {
                double cenaZa1Km;
                switch (p.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        cenaZa1Km = ceny[abonament ? 0 : 1];
                        break;
                    case DOSTAWCZY:
                        if (p.maxKilometry <= ceny[2]) {
                            cenaZa1Km = ceny[0];
                        } else {
                            cenaZa1Km = ceny[3];
                        }
                        break;
                    case ZABYTKOWY:
                        cenaZa1Km = ceny[0];
                        break;
                    case DARMO:
                        cenaZa1Km = 0;
                        break;
                    default:
                        cenaZa1Km = 0;
                }
                int maxKmDoZaplaty = (int) (nadmiar / cenaZa1Km);
                if (maxKmDoZaplaty < p.maxKilometry) {
                    p.maxKilometry = maxKmDoZaplaty;
                    nadmiar -= maxKmDoZaplaty * cenaZa1Km;
                } else {
                    nadmiar -= p.maxKilometry * cenaZa1Km;
                    doUsuniecia.add(p);
                }
            }
        }
        listaKoszyk.removeAll(doUsuniecia);
    }

    public void zwroc(TypPojazdu typ, String nazwa, int km) {
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(nazwa);
        if (ceny != null) {
            for (Pojazd p : listaKoszyk) {
                if (p.marka.equals(nazwa) && p.pobierzTypPojazdu() == typ) {
                    double cenaZa1Km;
                    switch (typ) {
                        case OSOBOWY:
                            cenaZa1Km = ceny[abonament ? 0 : 1];
                            break;
                        case DOSTAWCZY:
                            if (p.maxKilometry <= ceny[2]) {
                                cenaZa1Km = ceny[0];
                            } else {
                                cenaZa1Km = ceny[3];
                            }
                            break;
                        case ZABYTKOWY:
                            cenaZa1Km = ceny[0];
                            break;
                        case DARMO:
                            cenaZa1Km = 0;
                            break;
                        default:
                            cenaZa1Km = 0;
                    }
                    p.maxKilometry += km;
                    break;
                }
            }
        }
    }

    @Override
    public String toString() {
        StringBuilder result = new StringBuilder();
        if (listaKoszyk.isEmpty()) {
            return "-- pusto";
        }
        for (Pojazd p : listaKoszyk) {
            result.append(p.toString()).append("\n");
        }
        return result.toString();
    }
}

