                portfel = 0;
            } else {
                koszyk.wyczysc();
            }
        }
    }

    public void zwroc(TypPojazdu typ, String nazwa, int km) {
        koszyk.zwroc(typ, nazwa, km);
    }

    public String toStringZListaZyczen() {
        StringBuilder sb = new StringBuilder();
        sb.append("Lista życzeń klienta ").append(id).append(":\n");
        sb.append(listaZyczen.toString());
        return sb.toString();
    }
}

