abstract class Pojazd {
    protected String marka;
    protected int maxKilometry;

    public Pojazd(String marka, int maxKilometry) {
        this.marka = marka;
        this.maxKilometry = maxKilometry;
    }

    public abstract TypPojazdu pobierzTypPojazdu();

    @Override
    public String toString() {
        return marka + ", typ: " + getClass().getSimpleName().toLowerCase() + ", ile: " + maxKilometry + " km";
    }
}

class Osobowy extends Pojazd {
    public Osobowy(String marka, int maxKilometry) {
        super(marka, maxKilometry);
    }

    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.OSOBOWY;
    }
}

class Zabytkowy extends Pojazd {
    public Zabytkowy(String marka, int maxKilometry) {
        super(marka, maxKilometry);
    }

    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.ZABYTKOWY;
    }
}

class Dostawczy extends Pojazd {
    public Dostawczy(String marka, int maxKilometry) {
