}

enum MetodaPlatnosci {
    KARTA, PRZELEW
}

class Cennik {
    private static Cennik instance;
    private Map&lt;String, double[]&gt; ceny;

    private Cennik() {
        ceny = new HashMap&lt;&gt;();
    }

    public static Cennik pobierzCennik() {
        if (instance == null) {
            instance = new Cennik();
        }
        return instance;
    }

    public double[] pobierzCene(String nazwa) {
