```java
import java.util.ArrayList;
import java.util.List;

public class Koszyk {
    private List<Pojazd> listaKoszyk;
    private boolean abonament;

    public Koszyk(boolean abonament) {
        listaKoszyk = new ArrayList<>();
        this.abonament = abonament;
    }

    public double cena(String marka) {
        double cena = 0;
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(marka);

        if (ceny == null) {
            return 0; // Brak ceny dla danej marki
        }

        for (Pojazd pojazd : listaKoszyk) {
            if (pojazd.getMarka().equals(marka)) {
                double stawka = ceny[0]; // Stawka podstawowa
                double stawkaWyzsza = ceny[3]; // Stawka wyższa (jeśli istnieje)
                double limitKm = ceny[2]; // Limit kilometrów dla stawki podstawowej

                if (pojazd.pobierzTypPojazdu() == TypPojazdu.OSOBOWY && !abonament) {
                    stawka = ceny[1]; // Stawka wyższa dla pojazdów osobowych bez abonamentu
                }

                if (pojazd.maxKilometry <= limitKm) {
                    cena += pojazd.maxKilometry * stawka;
                } else {
                    cena += limitKm * stawka + (pojazd.maxKilometry - limitKm) * stawkaWyzsza;
                }
            }
        }

        return cena;
    }

    public double obliczCene(String markaSamochodu) {
        double sum = 0.0;
        for (Pojazd p : listaKoszyk) {
            if (p.getMarka().equals(markaSamochodu)) {
                sum += p.obliczCene(true);
            }
        }
        return sum;
    }

    public void wyczysc() {
        listaKoszyk.clear();
    }

    public void dodaj(Pojazd p) {
        listaKoszyk.add(p);
    }
}
```

