    }

    List<Pojazd> pojazdyDanejMarki = pobierzPojazdy(marka);
    for (Pojazd pojazd : pojazdyDanejMarki) {
        double stawka = ceny[abonament ? 0 : 1]; // Stawka podstawowa lub wyższa dla pojazdów osobowych bez abonamentu
        double stawkaWyzsza = ceny[3]; // Stawka wyższa (jeśli istnieje)
        double limitKm = ceny[2]; // Limit kilometrów dla stawki podstawowej

        if (pojazd.maxKilometry <= limitKm) {
            cena += pojazd.maxKilometry * stawka;
        } else {
            cena += limitKm * stawka + (pojazd.maxKilometry - limitKm) * stawkaWyzsza;
        }
    }

    return cena;
}
```

