import java.util.ArrayList;
import java.util.List;

public class Klient {
    private String id;
    private double portfel;
    private boolean abonament;
    private ListaZyczen listaZyczen;
    private Koszyk koszyk;

    public Klient(String id, double portfel, boolean abonament) {
        this.id = id;
        this.portfel = portfel;
        this.abonament = abonament;
        this.listaZyczen = new ListaZyczen(id);
        this.koszyk = new Koszyk(abonament,id);
    }

    public void dodaj(Pojazd pojazd) {
        listaZyczen.dodaj(pojazd);
    }

    public void przepakuj() {
        Cennik cennik = Cennik.pobierzCennik();
        Koszyk koszyk = pobierzKoszyk();
        ListaZyczen listaZyczen = pobierzListeZyczen();

        koszyk.wyczysc();

        List&lt;Pojazd&gt; listaZyczenCopy = new ArrayList&lt;&gt;(listaZyczen.pobierzListeZyczen());

        for(Pojazd p : listaZyczenCopy) {
            double[] ceny = cennik.pobierzCene(p.getMarka());
            if(ceny != null) {
                double cenaPojazdu = p.obliczCene(abonament);
                if (cenaPojazdu &lt;= portfel) {
                    koszyk.dodaj(p);
                    portfel -= cenaPojazdu;
                }
            }
        }
        for(Pojazd p : listaZyczenCopy) {
            if(!koszyk.pobierzPojazdy().contains(p)) {
                listaZyczen.usun(p);
            }
        }
    }

    public ListaZyczen pobierzListeZyczen() {
        return listaZyczen;
    }

    public Koszyk pobierzKoszyk() {
        return koszyk;
    }

    public void zaplac(MetodaPlatnosci metoda, boolean odkladaj) {
        double suma = 0;
        List&lt;Pojazd&gt; wszystkiePojazdy = koszyk.pobierzPojazdy();
        for(Pojazd p : wszystkiePojazdy) {
            suma += p.obliczCene(abonament);

        }
        double prowizja;
        if(MetodaPlatnosci.KARTA.equals(metoda)) {
            prowizja = suma*0.01;
        } else {
            prowizja = 0;
        }

        double kwotaDoZaplaty = suma + prowizja;
        double pozostalaSuma = kwotaDoZaplaty - portfel;

        if(kwotaDoZaplaty &lt;= portfel){
            portfel -= kwotaDoZaplaty;
            koszyk.wyczysc();
        }else if(odkladaj) {
            List&lt;Pojazd&gt; doOdlozenia = new ArrayList&lt;&gt;();

            while (kwotaDoZaplaty &gt; portfel) {
                Pojazd najdrozszyPojazd = null;
                double najdrozszaCena = 0;
                for (Pojazd p : wszystkiePojazdy) {
                    double cena = p.obliczCene(abonament);
                    if (cena &gt; najdrozszaCena) {
                        najdrozszyPojazd = p;
                        najdrozszaCena = cena;
                    }
                }

                if (najdrozszyPojazd != null) {
                    double cenaPojazdu = najdrozszyPojazd.obliczCene(abonament);
                    if (pozostalaSuma &gt;= cenaPojazdu &amp;&amp; portfel &gt;= cenaPojazdu) {
                        pozostalaSuma -= cenaPojazdu;
                        portfel -= cenaPojazdu;
                        wszystkiePojazdy.remove(najdrozszyPojazd);
                    } else {
                        doOdlozenia.add(najdrozszyPojazd);
                        koszyk.usun(najdrozszyPojazd);
                        listaZyczen.dodaj(najdrozszyPojazd);
                        wszystkiePojazdy.remove(najdrozszyPojazd);
                        kwotaDoZaplaty -= cenaPojazdu;
                    }
                }
            }
            for(Pojazd p : doOdlozenia) {
                listaZyczen.dodaj(p);
                koszyk.dodaj(p);
            }
        }else{
            listaZyczen.wyczysc();
            koszyk.wyczysc();
        }
        portfel -= prowizja;
    }


    public void zwroc(TypPojazdu typ, String nazwa, int km) {
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(nazwa);

        if(ceny!=null){
            Pojazd pojazd = null;
            switch (typ){
                case OSOBOWY:
                    pojazd = new Osobowy(nazwa,km);
                    break;
                    case DOSTAWCZY:
                        pojazd = new Dostawczy(nazwa, km);
                        break;
                case ZABYTKOWY:
                    pojazd = new Zabytkowy(nazwa, km);
                    break;
                case DARMO:
                    pojazd = new Darmowy(nazwa, km);
                    break;
            }
            if(pojazd != null) {
                koszyk.dodaj(pojazd);
                portfel += pojazd.obliczCene(abonament);
            }
        }
    }

    public double pobierzPortfel() {
        return portfel;
    }
}

