        if (ceny != null) {
            double cenaPojazdu = p.obliczCene(abonament);
            if (cenaPojazdu <= pozostalaSuma) {
                koszyk.dodaj(p);
                pozostalaSuma -= cenaPojazdu;
                listaZyczen.usun(p);
            }
        }
    }

    if (!listaZyczenCopy.isEmpty()) {
        Pojazd ostatniPojazd = listaZyczenCopy.get(listaZyczenCopy.size() - 1);
        double[] ceny = cennik.pobierzCene(ostatniPojazd.getMarka());
        if (ceny != null) {
            double cenaPojazdu = ostatniPojazd.obliczCene(abonament);
