    public void zaplac(MetodaPlatnosci metoda, boolean odkladaj) {
        double suma = 0;
        List&lt;Pojazd&gt; wszystkiePojazdy = new ArrayList&lt;&gt;(koszyk.pobierzPojazdy());
        for (Pojazd p : wszystkiePojazdy) {
            suma += p.obliczCene(abonament);
        }
        double prowizja;
        if (MetodaPlatnosci.KARTA.equals(metoda)) {
            prowizja = suma * 0.01;
        } else {
            prowizja = 0;
        }

        double kwotaDoZaplaty = suma + prowizja;
        double pozostalaSuma = kwotaDoZaplaty - portfel;

        if (kwotaDoZaplaty &lt;= portfel) {
            portfel -= kwotaDoZaplaty;
            koszyk.wyczysc();
        } else if (odkladaj) {
            List&lt;Pojazd&gt; doOdlozenia = new ArrayList&lt;&gt;();

            while (kwotaDoZaplaty &gt; portfel) {
                Pojazd najdrozszyPojazd = null;
                double najdrozszaCena = 0;
                for (Pojazd p : wszystkiePojazdy) {
                    double cena = p.obliczCene(abonament);
                    if (cena &gt; najdrozszaCena) {
                        najdrozszyPojazd = p;
                        najdrozszaCena = cena;
                    }
                }

                if (najdrozszyPojazd != null) {
                    double cenaPojazdu = najdrozszyPojazd.obliczCene(abonament);
                    Cennik cennik = Cennik.pobierzCennik();
                    if (pozostalaSuma &gt;= cenaPojazdu &amp;&amp; portfel &gt;= cenaPojazdu) {
                        pozostalaSuma -= cenaPojazdu;
                        portfel -= cenaPojazdu;
                        wszystkiePojazdy.remove(najdrozszyPojazd);
                        koszyk.usun(najdrozszyPojazd);
                    } else {
                        int maxKilometry = (int) (pozostalaSuma / cennik.pobierzCene(najdrozszyPojazd.getMarka())[0]);
                        if (maxKilometry &gt; 0) {
                            Pojazd zmniejszonyPojazd = null;
                            switch (najdrozszyPojazd.pobierzTypPojazdu()) {
                                case OSOBOWY:
                                    zmniejszonyPojazd = new Osobowy(najdrozszyPojazd.getMarka(), maxKilometry);
                                    break;
                                case DOSTAWCZY:
                                    zmniejszonyPojazd = new Dostawczy(najdrozszyPojazd.getMarka(), maxKilometry);
                                    break;
                                case ZABYTKOWY:
                                    zmniejszonyPojazd = new Zabytkowy(najdrozszyPojazd.getMarka(), maxKilometry);
                                    break;
                                case DARMO:
                                    zmniejszonyPojazd = new Darmowy(najdrozszyPojazd.getMarka(), maxKilometry);
                                    break;
                            }
                            if (zmniejszonyPojazd != null) {
                                koszyk.dodaj(zmniejszonyPojazd);
                                pozostalaSuma = 0;
                                portfel -= zmniejszonyPojazd.obliczCene(abonament);
                                wszystkiePojazdy.remove(najdrozszyPojazd);
                                int pozostaleKilometry = najdrozszyPojazd.maxKilometry - maxKilometry;
                                if (pozostaleKilometry &gt; 0) {
                                    Pojazd pozostalyPojazd = null;
                                    switch (najdrozszyPojazd.pobierzTypPojazdu()) {
                                        case OSOBOWY:
                                            pozostalyPojazd = new Osobowy(najdrozszyPojazd.getMarka(), pozostaleKilometry);
                                            break;
                                        case DOSTAWCZY:
                                            pozostalyPojazd = new Dostawczy(najdrozszyPojazd.getMarka(), pozostaleKilometry);
                                            break;
                                        case ZABYTKOWY:
                                            pozostalyPojazd = new Zabytkowy(najdrozszyPojazd.getMarka(), pozostaleKilometry);
                                            break;
                                        case DARMO:
                                            pozostalyPojazd = new Darmowy(najdrozszyPojazd.getMarka(), pozostaleKilometry);
                                            break;
                                    }
                                    if (pozostalyPojazd != null) {
                                        koszyk.dodaj(pozostalyPojazd);
                                    }
                                }
                                kwotaDoZaplaty -= zmniejszonyPojazd.obliczCene(abonament);
                            }
                        } else {
                            doOdlozenia.add(najdrozszyPojazd);
                            koszyk.usun(najdrozszyPojazd);
                            listaZyczen.dodaj(najdrozszyPojazd);
                            wszystkiePojazdy.remove(najdrozszyPojazd);
                            kwotaDoZaplaty -= cenaPojazdu;
                        }
                    }
                }
            }
            for (Pojazd p : doOdlozenia) {
                listaZyczen.dodaj(p);
                koszyk.dodaj(p);
            }
        } else {
            listaZyczen.wyczysc();
            koszyk.wyczysc();
        }
        portfel -= prowizja;
    }




    public void zwroc(TypPojazdu typ, String nazwa, int km) {
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(nazwa);

        if(ceny!=null){
            Pojazd pojazd = null;
            switch (typ){
                case OSOBOWY:
                    pojazd = new Osobowy(nazwa,km);
                    break;
                    case DOSTAWCZY:
                        pojazd = new Dostawczy(nazwa, km);
                        break;
                case ZABYTKOWY:
                    pojazd = new Zabytkowy(nazwa, km);
                    break;
                case DARMO:
                    pojazd = new Darmowy(nazwa, km);
                    break;
            }
            if(pojazd != null) {
                koszyk.dodaj(pojazd);
                portfel += pojazd.obliczCene(abonament);
            }
        }
    }

    public double pobierzPortfel() {
        return portfel;
    }
}

import java.util.ArrayList;
import java.util.List;

public class Koszyk {
    private List&lt;Pojazd&gt; listaKoszyk;
    private boolean abonament;

    private String idKlienta;

    public Koszyk(boolean abonament, String idKlienta) {
        listaKoszyk = new ArrayList&lt;&gt;();
        this.abonament = abonament;
        this.idKlienta=idKlienta;
    }

    public double cena(String marka){
        double cena = 0;
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(marka);

        if(ceny == null) {
            return 0;
        }

        for(Pojazd p : listaKoszyk){
            if (p.getMarka().equals(marka)) {
                double stawka;
                if(abonament){
                    stawka = ceny[0];
                }else{
                    stawka = ceny[1];
                }
                double stawkaPoLimicie = ceny[3];
                double limitkm = ceny[2];

                if(p.maxKilometry&lt;=limitkm){
                    cena+=p.maxKilometry*stawka;
                } else{
                    cena+= limitkm * stawka + (p.maxKilometry - limitkm) * stawkaPoLimicie;
                }
            }
        }
        return cena;
    }

    public List&lt;Pojazd&gt; pobierzPojazdy() {
        return new ArrayList&lt;&gt;(listaKoszyk);
    }


    public void wyczysc() {
        listaKoszyk.clear();
    }

    public void dodaj(Pojazd p) {
        listaKoszyk.add(p);
    }

    public void usun(Pojazd p){
        listaKoszyk.remove(p);
    }

    @Override
    public String toString() {
        if (listaKoszyk.isEmpty()) {
            return idKlienta + &quot;: --pusto&quot;;
        }
        StringBuilder sb = new StringBuilder();
        sb.append(this.idKlienta).append(&quot;:\n&quot;);
        for (Pojazd pojazd : listaKoszyk) {
            Cennik cennik = Cennik.pobierzCennik();
            double[] ceny = cennik.pobierzCene(pojazd.getMarka());
            String cenaStr = &quot;&quot;;
            if (ceny != null) {
                switch (pojazd.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        if (pojazd.maxKilometry &gt; ceny[2] &amp;&amp; ceny[2] != 0) {
                            cenaStr = &quot;cena &quot; + ceny[0] + &quot; (do &quot; + (int) ceny[2] + &quot;), &quot; + ceny[3] + &quot; (od &quot; + ((int) ceny[2] + 1) + &quot;)&quot;;
                            break;
                        } else {
                            cenaStr = &quot;cena &quot; + ceny[0];
                            break;
                        }
                    case DOSTAWCZY:
                        if (pojazd.maxKilometry &gt; ceny[2] &amp;&amp; ceny[2] != 0) {
                            cenaStr = &quot;cena &quot; + ceny[0] + &quot; (do &quot; + (int) ceny[2] + &quot;), &quot; + ceny[3] + &quot; (od &quot; + ((int) ceny[2] + 1) + &quot;)&quot;;
                            break;
                        } else {
                            cenaStr = &quot;cena &quot; + ceny[0];
                            break;
                        }
                    case ZABYTKOWY:
                        if (pojazd.maxKilometry &gt; ceny[2] &amp;&amp; ceny[2] != 0) {
                            cenaStr = &quot;cena &quot; + ceny[0] + &quot; (do &quot; + (int) ceny[2] + &quot;), &quot; + ceny[3] + &quot; (od &quot; + ((int) ceny[2] + 1) + &quot;)&quot;;
                            break;
                        } else {
                            cenaStr = &quot;cena &quot; + ceny[0];
                            break;
                        }
                    case DARMO:
                        cenaStr = &quot;ceny &quot; + ceny[0];
                        break;
                }
            } else {
                cenaStr = &quot;ceny brak&quot;;
            }
            sb.append(pojazd).append(&quot;, &quot;).append(cenaStr).append(&quot;\n&quot;);
        }

        return sb.toString();
    }

}

