    double pozostalaSuma = kwotaDoZaplaty - portfel;

    if (kwotaDoZaplaty <= portfel) {
        portfel -= kwotaDoZaplaty;
        koszyk.wyczysc();
    } else {
        List<Pojazd> zmniejszonePojazdy = new ArrayList<>();
        for (Pojazd p : wszystkiePojazdy) {
            double cenaPojazdu = p.obliczCene(abonament);
            if (pozostalaSuma >= cenaPojazdu) {
                pozostalaSuma -= cenaPojazdu;
                portfel -= cenaPojazdu;
                zmniejszonePojazdy.add(p);
            } else {
                int maxKilometry = (int) (pozostalaSuma / cennik.pobierzCene(p.getMarka())[0]);
                if (maxKilometry > 0) {
                    Pojazd zmniejszonyPojazd = null;
                    switch (p.pobierzTypPojazdu()) {
                        case OSOBOWY:
                            zmniejszonyPojazd = new Osobowy(p.getMarka(), maxKilometry);
                            break;
                        case DOSTAWCZY:
                            zmniejszonyPojazd = new Dostawczy(p.getMarka(), maxKilometry);
                            break;
                        case ZABYTKOWY:
                            zmniejszonyPojazd = new Zabytkowy(p.getMarka(), maxKilometry);
                            break;
                        case DARMO:
                            zmniejszonyPojazd = new Darmowy(p.getMarka(), maxKilometry);
                            break;
                    }
                    if (zmniejszonyPojazd != null) {
                        zmniejszonePojazdy.add(zmniejszonyPojazd);
                        pozostalaSuma = 0;
                        portfel -= zmniejszonyPojazd.obliczCene(abonament);
                        int pozostaleKilometry = p.maxKilometry - maxKilometry;
                        if (pozostaleKilometry > 0) {
                            Pojazd pozostalyPojazd = null;
                            switch (p.pobierzTypPojazdu()) {
                                case OSOBOWY:
                                    pozostalyPojazd = new Osobowy(p.getMarka(), pozostaleKilometry);
                                    break;
                                case DOSTAWCZY:
                                    pozostalyPojazd = new Dostawczy(p.getMarka(), pozostaleKilometry);
                                    break;
                                case ZABYTKOWY:
                                    pozostalyPojazd = new Zabytkowy(p.getMarka(), pozostaleKilometry);
                                    break;
                                case DARMO:
                                    pozostalyPojazd = new Darmowy(p.getMarka(), pozostaleKilometry);
                                    break;
                            }
                            if (pozostalyPojazd != null) {
                                koszyk.dodaj(pozostalyPojazd);
                            }
                        }
                    }
                }
            }
        }
        koszyk.wyczysc();
        koszyk.dodajPojazdy(zmniejszonePojazdy);
    }
    portfel -= prowizja;
}
```

Zmiany:

1. Dodałem blok `else`, który obsługuje sytuację, gdy kwota do zapłaty przekracza budżet klienta.
2. Utworzyłem nową listę `zmniejszonePojazdy`, do której będą dodawane pojazdy, na które klient ma wystarczający budżet, oraz pojazdy ze zmniejszoną liczbą kilometrów.
3. Dla każdego pojazdu, na który klient nie ma wystarczającego budżetu, tworzę nowy pojazd ze zmniejszoną liczbą kilometrów i dodaję go do listy `zmniejszonePojazdy`.
4. Jeśli po zmniejszeniu liczby kilometrów pozostała jakaś część kilometrów, tworzę nowy pojazd z tą pozostałą liczbą kilometrów i dodaję go z powrotem do koszyka.
5. Po przetworzeniu wszystkich pojazdów, czyszczę koszyk i dodaję do niego pojazdy z listy `zmniejszonePojazdy`.

Dzięki tej implementacji, metoda `zaplac()` będzie działać w następujący sposób:

1. Jeśli klient ma wystarczający budżet, opłaci całe zamówienie i wyczyści koszyk.
2. Jeśli klient nie ma wystarczającego budżetu, opłaci tyle pojazdów, na ile go stać, zmniejszając liczbę kilometrów, jeśli to konieczne. Pozostałe kilometry zostaną dodane z powrotem do koszyka jako nowe pojazdy.

