        while (pozostalaSuma > 0 && !wszystkiePojazdy.isEmpty()) {
            Pojazd najdrozszyPojazd = wszystkiePojazdy.stream()
                    .max(Comparator.comparingDouble(p -> p.obliczCene(abonament)))
                    .orElse(null);

