public void zaplac(MetodaPlatnosci metoda, boolean odkladaj) {
    Cennik cennik = Cennik.pobierzCennik();
    double suma = 0;
    List<Pojazd> wszystkiePojazdy = new ArrayList<>(koszyk.pobierzPojazdy());
    for (Pojazd p : wszystkiePojazdy) {
        suma += p.obliczCene(abonament, p.maxKilometry);
    }
    double prowizja;
    if (MetodaPlatnosci.KARTA.equals(metoda)) {
        prowizja = suma * 0.01;
    } else {
        prowizja = 0;
    }

    double kwotaDoZaplaty = suma + prowizja;
    double pozostalaSuma = kwotaDoZaplaty - portfel;

    if (kwotaDoZaplaty <= portfel) {
        portfel -= kwotaDoZaplaty;
        koszyk.wyczysc();
    } else if (odkladaj) {
        List<Pojazd> zmniejszonePojazdy = new ArrayList<>();

        while (pozostalaSuma > 0 && !wszystkiePojazdy.isEmpty()) {
            Pojazd najdrozszyPojazd = null;
            double najdrozszaCena = 0;
            for (Pojazd p : wszystkiePojazdy) {
                double cena = p.obliczCene(abonament, p.maxKilometry);
                if (cena > najdrozszaCena) {
                    najdrozszyPojazd = p;
                    najdrozszaCena = cena;
                }
            }

            if (najdrozszyPojazd != null) {
                double cenaPojazdu = najdrozszyPojazd.obliczCene(abonament, najdrozszyPojazd.maxKilometry);

                if (pozostalaSuma >= cenaPojazdu && portfel >= cenaPojazdu) {
                    pozostalaSuma -= cenaPojazdu;
                    portfel -= cenaPojazdu;
                    zmniejszonePojazdy.add(najdrozszyPojazd);
                    wszystkiePojazdy.remove(najdrozszyPojazd);
                } else {
                    double[] ceny = cennik.pobierzCene(najdrozszyPojazd.getMarka());
                    if (ceny != null) {
                        double stawka = abonament ? ceny[0] : ceny[1];
                        double stawkaPoLimicie = ceny[3];
                        double limitkm = ceny[2];

                        int resztakm = (int) (pozostalaSuma / stawka);
                        if (resztakm > 0 && resztakm <= limitkm) {
                            Pojazd zmniejszonyPojazd = utworzPojazd(najdrozszyPojazd.pobierzTypPojazdu(), najdrozszyPojazd.getMarka(), resztakm);
                            if (zmniejszonyPojazd != null) {
                                zmniejszonePojazdy.add(zmniejszonyPojazd);
                                double cenaZmniejszonegoPojazdu = zmniejszonyPojazd.obliczCene(abonament, resztakm);
                                pozostalaSuma -= cenaZmniejszonegoPojazdu;
                                portfel -= cenaZmniejszonegoPojazdu;
                                kwotaDoZaplaty -= cenaZmniejszonegoPojazdu;
                                wszystkiePojazdy.remove(najdrozszyPojazd);
                            }
                        } else if (resztakm > limitkm) {
                            int resztakmPoLimicie = resztakm - limitkm;
                            Pojazd zmniejszonyPojazd = utworzPojazd(najdrozszyPojazd.pobierzTypPojazdu(), najdrozszyPojazd.getMarka(), limitkm + resztakmPoLimicie);
                            if (zmniejszonyPojazd != null) {
                                zmniejszonePojazdy.add(zmniejszonyPojazd);
                                double cenaZmniejszonegoPojazdu = zmniejszonyPojazd.obliczCene(abonament, limitkm + resztakmPoLimicie);
                                pozostalaSuma -= cenaZmniejszonegoPojazdu;
                                portfel -= cenaZmniejszonegoPojazdu;
                                kwotaDoZaplaty -= cenaZmniejszonegoPojazdu;
                                wszystkiePojazdy.remove(najdrozszyPojazd);
                            }
                        } else {
                            wszystkiePojazdy.remove(najdrozszyPojazd);
                        }
                    }
                }
            }
        }
        koszyk.wyczysc();
        koszyk.dodajPojazdy(zmniejszonePojazdy);
    } else {
        koszyk.wyczysc();
    }
    portfel -= prowizja;
}

