                            if (zmniejszonyPojazd != null) {
                                double cenaZmniejszonegoPojazdu = zmniejszonyPojazd.obliczCene(abonament);
                                zmniejszonePojazdy.add(zmniejszonyPojazd);
                                pozostalaSuma -= cenaZmniejszonegoPojazdu;
                                portfel -= cenaZmniejszonegoPojazdu;
                                kwotaDoZaplaty -= cenaZmniejszonegoPojazdu;
                                wszystkiePojazdy.remove(najdrozszyPojazd);
                            }
                        } else if (resztakm > limitkm) {
                            int resztakmPoLimicie = resztakm - limitkm;
                            Pojazd zmniejszonyPojazd = utworzPojazd(najdrozszyPojazd.pobierzTypPojazdu(), najdrozszyPojazd.getMarka(), limitkm + resztakmPoLimicie);
                            if (zmniejszonyPojazd != null) {
                                double cenaZmniejszonegoPojazdu = zmniejszonyPojazd.obliczCene(abonament);
                                zmniejszonePojazdy.add(zmniejszonyPojazd);
                                pozostalaSuma -= cenaZmniejszonegoPojazdu;
                                portfel -= cenaZmniejszonegoPojazdu;
                                kwotaDoZaplaty -= cenaZmniejszonegoPojazdu;
                                wszystkiePojazdy.remove(najdrozszyPojazd);
                            }
                        } else {
                            wszystkiePojazdy.remove(najdrozszyPojazd);
                        }
                    }
                }
            }
        }
        koszyk.wyczysc();
        koszyk.dodajPojazdy(zmniejszonePojazdy);
    } else {
        koszyk.wyczysc();
    }
    portfel -= prowizja;
}

public void zwroc(TypPojazdu typ, String nazwa, int km) {
    Cennik cennik = Cennik.pobierzCennik();
    double[] ceny = cennik.pobierzCene(nazwa);

    if (ceny != null) {
        Pojazd pojazd = utworzPojazd(typ, nazwa, km);
        if (pojazd != null) {
            List<Pojazd> pojazdyWKoszyku = koszyk.pobierzPojazdy();
            boolean znaleziono = false;
            for (Pojazd p : pojazdyWKoszyku) {
                if (p.getMarka().equals(nazwa) && p.pobierzTypPojazdu() == typ) {
                    int nowaLiczbaKm = p.maxKilometry + km;
                    Pojazd nowyPojazd = utworzPojazd(typ, nazwa, nowaLiczbaKm);
                    if (nowyPojazd != null) {
                        double staraCena = p.obliczCene(abonament);
                        double nowaCena = nowyPojazd.obliczCene(abonament);
                        koszyk.usun(p);
                        koszyk.dodaj(nowyPojazd);
                        portfel += nowaCena - staraCena;
                        znaleziono = true;
                        break;
                    }
                }
            }
            if (!znaleziono) {
                koszyk.dodaj(pojazd);
                portfel += pojazd.obliczCene(abonament);
            }
        }
    }
}
