                double cenaPojazdu = najdrozszyPojazd.obliczCene(abonament);

                if (pozostalaSuma >= cenaPojazdu && portfel >= cenaPojazdu) {
                    pozostalaSuma -= cenaPojazdu;
                    portfel -= cenaPojazdu;
                    zmniejszonePojazdy.add(najdrozszyPojazd);
                    wszystkiePojazdy.remove(najdrozszyPojazd);
                } else {
                    double najnizszaCenaZaKm = Double.MAX_VALUE;
                    Pojazd najtanszaPozostalosc = null;
                    for (Pojazd p : wszystkiePojazdy) {
                        double[] ceny = cennik.pobierzCene(p.getMarka());
                        if (ceny != null) {
                            double cenaZaKm = ceny[0];
                            if (cenaZaKm < najnizszaCenaZaKm) {
                                najnizszaCenaZaKm = cenaZaKm;
                                najtanszaPozostalosc = p;
                            }
                        }
                    }

                    if (najtanszaPozostalosc != null) {
                        int resztakm = (int) (pozostalaSuma / najnizszaCenaZaKm);
                        if (resztakm > 0) {
                            Pojazd zmniejszonyPojazd = utworzPojazd(najtanszaPozostalosc.pobierzTypPojazdu(), najtanszaPozostalosc.getMarka(), resztakm);
                            if (zmniejszonyPojazd != null) {
                                zmniejszonePojazdy.add(zmniejszonyPojazd);
                                pozostalaSuma = 0;
                                portfel -= zmniejszonyPojazd.obliczCene(abonament);
                                kwotaDoZaplaty -= zmniejszonyPojazd.obliczCene(abonament);
                                wszystkiePojazdy.remove(najtanszaPozostalosc);
                            }
                        } else {
                            wszystkiePojazdy.remove(najtanszaPozostalosc);
                        }
                    }
                }
            }
        }
        koszyk.wyczysc();
        koszyk.dodajPojazdy(zmniejszonePojazdy);
    } else {
        koszyk.wyczysc();
    }
    portfel -= prowizja;
}
```

