private Pojazd utworzPojazd(TypPojazdu typ, String marka, int km) {
    Pojazd pojazd = null;
    Cennik cennik = Cennik.pobierzCennik();
    double[] ceny = cennik.pobierzCene(marka);

    if (ceny != null) {
        double limitkm = ceny[2];
        switch (typ) {
            case OSOBOWY:
                if (km <= limitkm) {
                    pojazd = new Osobowy(marka, km);
                } else {
                    pojazd = new Osobowy(marka, (int) limitkm);
                }
                break;
            case DOSTAWCZY:
                if (km <= limitkm) {
                    pojazd = new Dostawczy(marka, km);
                } else {
                    pojazd = new Dostawczy(marka, (int) limitkm);
                }
                break;
            case ZABYTKOWY:
                if (km <= limitkm) {
                    pojazd = new Zabytkowy(marka, km);
                } else {
                    pojazd = new Zabytkowy(marka, (int) limitkm);
                }
                break;
            case DARMO:
                pojazd = new Darmowy(marka, km);
                break;
        }
    }
    return pojazd;
}
```

