Na podstawie kodu i komentarzy, widzę, że głównym problemem jest niepoprawne obliczanie `pozostalaSuma` i `pozostalePortfel`. Oto sugerowane zmiany:

```java
public void zaplac(MetodaPlatnosci metoda, boolean odkladaj) {
    Cennik cennik = Cennik.pobierzCennik();
    double suma = 0;
    List<Pojazd> wszystkiePojazdy = new ArrayList<>(koszyk.pobierzPojazdy());
    for (Pojazd p : wszystkiePojazdy) {
        suma += p.obliczCene(abonament);
    }

    double prowizja = MetodaPlatnosci.KARTA.equals(metoda) ? suma * 0.01 : 0;
    double kwotaDoZaplaty = suma + prowizja;

    if (kwotaDoZaplaty <= portfel) {
        portfel -= kwotaDoZaplaty;
        koszyk.wyczysc();
    } else if (odkladaj) {
        double pozostalaSuma = kwotaDoZaplaty - portfel; // Obliczanie pozostalaSuma jako różnicy między kwotaDoZaplaty a portfel
        double pozostalePortfel = portfel - prowizja; // Obliczanie pozostalePortfel jako portfel pomniejszony o prowizję

        for (Pojazd p : wszystkiePojazdy) {
            double cenaPojazdu = p.obliczCene(abonament);
            if (cenaPojazdu > pozostalePortfel) {
                pozostalaSuma += cenaPojazdu;
                pozostalePortfel = 0;
            } else {
                pozostalePortfel -= cenaPojazdu;
            }
        }

        double najtanszaCenaZaKm = Double.MAX_VALUE;
        Pojazd najtanszaPozostalosc = null;
        for (Pojazd p : wszystkiePojazdy) {
            double[] ceny = cennik.pobierzCene(p.getMarka());
            if (ceny != null && ceny[0] < najtanszaCenaZaKm) {
                najtanszaCenaZaKm = ceny[0];
                najtanszaPozostalosc = p;
            }
        }

        if (najtanszaPozostalosc != null) {
            int resztakm = (int) Math.floor(pozostalaSuma / najtanszaCenaZaKm);
            double[] ceny = cennik.pobierzCene(najtanszaPozostalosc.getMarka());
            int limitKm = (int) ceny[2];

            Pojazd zmniejszonyPojazd = utworzPojazd(najtanszaPozostalosc.pobierzTypPojazdu(), najtanszaPozostalosc.getMarka(), Math.min(resztakm, limitKm));
            if (zmniejszonyPojazd != null) {
                koszyk.wyczysc();
                koszyk.dodaj(zmniejszonyPojazd);
                portfel -= zmniejszonyPojazd.obliczCene(abonament);
            }
        }
    } else {
        koszyk.wyczysc();
    }
    portfel -= prowizja;
}
```

Zmiany:

1. `pozostalaSuma` jest obliczana jako różnica między `kwotaDoZaplaty` a `portfel`. Dzięki temu, `pozostalaSuma` będzie zawsze poprawnie odzwierciedlać kwotę, której klient nie może zapłacić.
2. `pozostalePortfel` jest obliczana jako `portfel` pomniejszony o `prowizję`. Dzięki temu, `pozostalePortfel` będzie zawierać kwotę, którą klient może przeznaczyć na opłacenie pojazdów.
3. Pętla obliczająca `pozostalaSuma` i `pozostalePortfel` została przeniesiona poniżej, aby korzystać z poprawnych wartości.

Dzięki tym zmianom, `pozostalaSuma` i `pozostalePortfel` powinny być obliczane poprawnie, co powinno umożliwić prawidłowe działanie pozostałej części kodu.

public class Main {

                // cena samochodów danego typu z koszyka
    static double cena(Koszyk k, String markaSamochodu) {
        return k.cena(markaSamochodu);
    }

    public static void main(String[] args) {

        // cennik
        Cennik cennik = Cennik.pobierzCennik();

        // dodawanie nowych cen do cennika
        cennik.dodaj(TypPojazdu.OSOBOWY, &quot;Syrena&quot;, 1.5, 2.5, 100, 1.85);  // 1.5 zł za 1 km jeśli klient posiada abonament,
        // w przeciwnym przypadku: 2.5 zł za 1 km (do 100 km), 1.85 zł za 1 km (od 101-ego kilometra)

        cennik.dodaj(TypPojazdu.DOSTAWCZY, &quot;Żuk&quot;, 4, 150, 3);	// 4 zł za 1 km (do 150 km),
        // 3 zł za 1 km (od 151-tego kilometra)

        cennik.dodaj(TypPojazdu.ZABYTKOWY, &quot;Ford T&quot;, 10);		// 10 zł za 1 km


        cennik.dodaj(TypPojazdu.DARMO, 50, &quot;Tuk-Tuk&quot;);		// darmowy przejazd tylko dla abonentów (do 50 km)


        // Klient f1 deklaruje kwotę 900 zł na zamównienia; true oznacza, że klient posiada abonament
        Klient f1 = new Klient(&quot;f1&quot;, 900, true);

        // Klient f1 dodaje do listy życzeń różne samochody:
        // &quot;Syrena&quot; typu osobowego na maks. 80 km
        // &quot;Żuk&quot; typu dostawczego na maks. 200 km,
        // &quot;Lublin&quot; typu zabytkowego na maks. 30 km,
        // &quot;Tuk-Tuk&quot; typu darmowego na maks. 60 km (ale może tylko do 50 km).
        f1.dodaj(new Osobowy(&quot;Syrena&quot;, 80));
        f1.dodaj(new Dostawczy(&quot;Żuk&quot;, 200));
        f1.dodaj(new Zabytkowy(&quot;Lublin&quot;, 30));
        f1.dodaj(new Darmowy(&quot;Tuk-Tuk&quot;, 60));

        // Lista życzeń klienta f1
        ListaZyczen listaF1 = f1.pobierzListeZyczen();

        System.out.println(&quot;Lista życzeń klienta &quot; + listaF1);

        // Przed płaceniem, klient przepakuje samochody z listy życzeń do koszyka (po uprzednim wyczyszczeniu).
        // Możliwe, że na liście życzeń są samochody niemające ceny w cenniku,
        // w takim przypadku nie trafiłyby do koszyka
        Koszyk koszykF1 = f1.pobierzKoszyk();
        f1.przepakuj();

        // Co jest na liście życzeń klienta f1
        System.out.println(&quot;Po przepakowaniu, lista życzeń klienta &quot; + f1.pobierzListeZyczen());

        // Co jest w koszyku klienta f1
        System.out.println(&quot;Po przepakowaniu, koszyk klienta &quot; + koszykF1);

        // Ile wynosi cena wszystkich samochodów typu osobowego w koszyku klienta f1
        System.out.println(&quot;Samochody Syrena w koszyku klienta f1 kosztowały:  &quot; + cena(koszykF1, &quot;Syrena&quot;));

        // Klient zapłaci...
        f1.zaplac(MetodaPlatnosci.KARTA, false);	// płaci kartą płatniczą, prowizja 1%
        // true oznacza, że w przypadku braku środków aplikacja sam odłoży nadmiarowe kilometry/samochody,
        // false oznacza rezygnację z płacenia razem z wyczyszczeniem koszyka i listy życzeń

        // Ile klientowi f1 zostało pieniędzy?
        System.out.println(&quot;Po zapłaceniu, klientowi f1 zostało: &quot; + f1.pobierzPortfel() + &quot; zł&quot;);

        // Mogło klientowi zabraknąć srodków, wtedy, opcjonalnie, samochody/kilometry mogą być odkładane,
        // w przeciwnym przypadku, koszyk jest pusty po zapłaceniu
        System.out.println(&quot;Po zapłaceniu, koszyk klienta &quot; + f1.pobierzKoszyk());
        System.out.println(&quot;Po zapłaceniu, koszyk klienta &quot; + koszykF1);

        // Teraz przychodzi klient dakar,
        // deklaruje 850 zł na zamówienia
        Klient dakar = new Klient(&quot;dakar&quot;, 850, false);

        // Zamówił za dużo jak na tę kwotę
        dakar.dodaj(new Dostawczy(&quot;Żuk&quot;, 100));
        dakar.dodaj(new Zabytkowy(&quot;Ford T&quot;, 50));

        // Co klient dakar ma na swojej liście życzeń
        System.out.println(&quot;Lista życzeń klienta &quot; + dakar.pobierzListeZyczen());

        Koszyk koszykDakar = dakar.pobierzKoszyk();
        dakar.przepakuj();

        // Co jest na liście życzeń klienta dakar
        System.out.println(&quot;Po przepakowaniu, lista życzeń klienta &quot; + dakar.pobierzListeZyczen());

        // A co jest w koszyku klienta dakar
        System.out.println(&quot;Po przepakowaniu, koszyk klienta &quot; + dakar.pobierzKoszyk());

        // klient dakar płaci
        dakar.zaplac(MetodaPlatnosci.PRZELEW, true);	// płaci przelewem, bez prowizji

        // Ile klientowi dakar zostało pieniędzy?
        System.out.println(&quot;Po zapłaceniu, klientowi dakar zostało: &quot; + dakar.pobierzPortfel() + &quot; zł&quot;);

        // Co zostało w koszyku klienta dakar (za mało pieniędzy miał)
        System.out.println(&quot;Po zapłaceniu, koszyk klienta &quot; + koszykDakar);

        dakar.zwroc(TypPojazdu.DOSTAWCZY, &quot;Żuk&quot;, 50);	// zwrot (do koszyka) 50 km dostawczego &quot;Żuka&quot; z ostatniej transakcji

        // Ile klientowi dakar zostało pieniędzy?
        System.out.println(&quot;Po zwrocie, klientowi dakar zostało: &quot; + dakar.pobierzPortfel() + &quot; zł&quot;);

        // Co zostało w koszyku klienta dakar
        System.out.println(&quot;Po zwrocie, koszyk klienta &quot; + koszykDakar);

    }
}

public abstract class Pojazd {
    protected String marka;
    protected int maxKilometry;

    public Pojazd(String marka, int maxKilometry) {
        this.marka = marka;
        this.maxKilometry = maxKilometry;
    }

    public double obliczCene(boolean abonament){
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(marka);

        if(ceny == null) {
            return 0;
        }
        double stawka;
        double stawkaPoLimicie = ceny[3];
        double limitkm = ceny[2];

        if (abonament){
            stawka = ceny[0];
        } else {
            stawka = ceny[1];
        }

        if(maxKilometry&lt;= limitkm) {
            return stawka * maxKilometry;
        } else {
            return limitkm * stawka + (maxKilometry - limitkm) * stawkaPoLimicie;
        }
    }

    public double obliczCeneZKm(boolean abonament, int km){
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(marka);

        if(ceny == null) {
            return 0;
        }
        double stawka;
        double stawkaPoLimicie = ceny[3];
        double limitkm = ceny[2];

        if (abonament){
            stawka = ceny[0];
        } else {
            stawka = ceny[1];
        }

        if (km &lt;= limitkm) {
            return stawka * km;
        } else {
            return limitkm * stawka + (km - limitkm) * stawkaPoLimicie;
        }
    }



    public abstract TypPojazdu pobierzTypPojazdu();

    public String getMarka() {
        return marka;
    }


    @Override
    public String toString() {
        return marka + &quot;, typ: &quot; + getClass().getSimpleName().toLowerCase() + &quot;, ile: &quot; + maxKilometry + &quot; km&quot;;
    }
}


public class Osobowy extends Pojazd {
    public Osobowy(String marka, int maxKilometry) {
        super(marka, maxKilometry);
    }

    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.OSOBOWY;
    }


    @Override
    public double obliczCene(boolean maAbonament) {
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(this.marka);
        double cenakoncowa = 0;
        if (ceny != null) {
            if (maAbonament) {
                cenakoncowa = ceny[0] * this.maxKilometry;
            } else if (this.maxKilometry &lt;= ceny[2] &amp;&amp; ceny[2] != 0) {
                cenakoncowa = ceny[1] * this.maxKilometry;
            } else {
                cenakoncowa = ceny[1] * ceny[2] + ceny[3] * (this.maxKilometry - ceny[2]);
            }
            return cenakoncowa;
        }
        return 0; // brak ceny w cenniku
    }
}

public class Darmowy extends Pojazd {
    public Darmowy(String marka, int maxKilometry) {
        super(marka, Math.min(maxKilometry, 50));
    }

    @Override
    public double obliczCene(boolean abonament) {
        return 0;
    }


    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.DARMO;
    }
}

public class Zabytkowy extends Pojazd {
    public Zabytkowy(String marka, int maxKilometry) {
        super(marka, maxKilometry);
    }

    @Override
    public double obliczCene(boolean abonament) {
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(this.marka);
        if(ceny!=null){
            return ceny[0] * this.maxKilometry;
        }
        return 0; //brak ceny w cenniku
    }



    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.ZABYTKOWY;
    }
}
public class Dostawczy extends Pojazd {
    public Dostawczy(String marka, int maxKilometry) {
        super(marka, maxKilometry);
    }

    @Override
    public double obliczCene(boolean maAbonament) {
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(this.marka);
        double cenakoncowa = 0;
        if (ceny != null) {
           if (this.maxKilometry &lt;= ceny[2] &amp;&amp; ceny[2] != 0) {
                cenakoncowa = ceny[0] * this.maxKilometry;
            } else {
                cenakoncowa = ceny[0] * ceny[2] + ceny[3] * (this.maxKilometry - ceny[2]);
            }
            return cenakoncowa;
        }
        return 0; // brak ceny w cenniku
    }

    @Override
    public TypPojazdu pobierzTypPojazdu() {
        return TypPojazdu.DOSTAWCZY;
    }
}

import java.util.HashMap;
import java.util.Map;

public class Cennik {
    private static Cennik instance;
    private Map&lt;String, double[]&gt; ceny;

    private Cennik() {
        ceny = new HashMap&lt;&gt;();
    }

    public static Cennik pobierzCennik() {
        if (instance == null) {
            instance = new Cennik();
        }
        return instance;
    }


    public double[] pobierzCene(String nazwa) {
        return ceny.get(nazwa);
    }

    public void dodaj(TypPojazdu typ, String nazwa, double cenaZAbonamentem, double cenaBezAbonamentu, int limitKm, double cenaPoLimicie) {
        ceny.put(nazwa, new double[]{cenaZAbonamentem, cenaBezAbonamentu, (double) limitKm, cenaPoLimicie});
    }

    public void dodaj(TypPojazdu typ, String nazwa, double cenaDoLimitu, int limitKm, double cenaPoLimicie) {
        ceny.put(nazwa, new double[]{cenaDoLimitu, cenaDoLimitu, (double) limitKm, cenaPoLimicie});
    }

    public void dodaj(TypPojazdu typ, String nazwa, double cenaZaKm) {
        ceny.put(nazwa, new double[]{cenaZaKm, cenaZaKm, 0, cenaZaKm});
    }

    public void dodaj(TypPojazdu typ, int limitKm, String nazwa) {
        ceny.put(nazwa, new double[]{0, 0, (double) limitKm, 0});
    }


}

import java.util.ArrayList;
import java.util.List;

public class Koszyk {
    private List&lt;Pojazd&gt; listaKoszyk;
    private boolean abonament;

    private String idKlienta;

    public Koszyk(boolean abonament, String idKlienta) {
        listaKoszyk = new ArrayList&lt;&gt;();
        this.abonament = abonament;
        this.idKlienta=idKlienta;
    }

    public double cena(String marka){
        double cena = 0;
        Cennik cennik = Cennik.pobierzCennik();
        double[] ceny = cennik.pobierzCene(marka);

        if(ceny == null) {
            return 0;
        }

        for(Pojazd p : listaKoszyk){
            if (p.getMarka().equals(marka)) {
                double stawka;
                if(abonament){
                    stawka = ceny[0];
                }else{
                    stawka = ceny[1];
                }
                double stawkaPoLimicie = ceny[3];
                double limitkm = ceny[2];

                if(p.maxKilometry&lt;=limitkm){
                    cena+=p.maxKilometry*stawka;
                } else{
                    cena+= limitkm * stawka + (p.maxKilometry - limitkm) * stawkaPoLimicie;
                }
            }
        }
        return cena;
    }

    public List&lt;Pojazd&gt; pobierzPojazdy() {
        return new ArrayList&lt;&gt;(listaKoszyk);
    }


    public void wyczysc() {
        listaKoszyk.clear();
    }

    public void dodaj(Pojazd p) {
        listaKoszyk.add(p);
    }

    public void usun(Pojazd p){
        listaKoszyk.remove(p);
    }

    @Override
    public String toString() {
        if (listaKoszyk.isEmpty()) {
            return idKlienta + &quot;: --pusto&quot;;
        }
        StringBuilder sb = new StringBuilder();
        sb.append(this.idKlienta).append(&quot;:\n&quot;);
        for (Pojazd pojazd : listaKoszyk) {
            Cennik cennik = Cennik.pobierzCennik();
            double[] ceny = cennik.pobierzCene(pojazd.getMarka());
            String cenaStr = &quot;&quot;;
            if (ceny != null) {
                switch (pojazd.pobierzTypPojazdu()) {
                    case OSOBOWY:
                        if (pojazd.maxKilometry &gt; ceny[2] &amp;&amp; ceny[2] != 0) {
                            cenaStr = &quot;cena &quot; + ceny[0] + &quot; (do &quot; + (int) ceny[2] + &quot;), &quot; + ceny[3] + &quot; (od &quot; + ((int) ceny[2] + 1) + &quot;)&quot;;
                            break;
                        } else {
                            cenaStr = &quot;cena &quot; + ceny[0];
                            break;
                        }
                    case DOSTAWCZY:
                        if (pojazd.maxKilometry &gt; ceny[2] &amp;&amp; ceny[2] != 0) {
                            cenaStr = &quot;cena &quot; + ceny[0] + &quot; (do &quot; + (int) ceny[2] + &quot;), &quot; + ceny[3] + &quot; (od &quot; + ((int) ceny[2] + 1) + &quot;)&quot;;
                            break;
                        } else {
                            cenaStr = &quot;cena &quot; + ceny[0];
                            break;
                        }
                    case ZABYTKOWY:
                        if (pojazd.maxKilometry &gt; ceny[2] &amp;&amp; ceny[2] != 0) {
                            cenaStr = &quot;cena &quot; + ceny[0] + &quot; (do &quot; + (int) ceny[2] + &quot;), &quot; + ceny[3] + &quot; (od &quot; + ((int) ceny[2] + 1) + &quot;)&quot;;
                            break;
                        } else {
                            cenaStr = &quot;cena &quot; + ceny[0];
                            break;
                        }
                    case DARMO:
                        cenaStr = &quot;ceny &quot; + ceny[0];
                        break;
                }
            } else {
                cenaStr = &quot;ceny brak&quot;;
            }
            sb.append(pojazd).append(&quot;, &quot;).append(cenaStr).append(&quot;\n&quot;);
        }

        return sb.toString();
    }

    public void dodajPojazdy(List&lt;Pojazd&gt; pojazdy) {
        for (Pojazd p : pojazdy) {
            listaKoszyk.add(p);
        }
    }


}

