            if (cenaPojazdu <= portfel) {
                koszyk.dodaj(p);
                portfel -= cenaPojazdu;
                listaZyczen.usun(p);
            } else {
                int maxKilometry = (int) (portfel / ceny[0]);
                if (maxKilometry > 0) {
