        zmniejszonePojazdy.add(zmniejszonyPojazd);
        double cenaZmniejszonegoPojazdu = zmniejszonyPojazd.obliczCene(abonament);
        pozostalaKwotaDoZaplaty -= cenaZmniejszonegoPojazdu;
        portfel -= cenaZmniejszonegoPojazdu;
